# =============================================================================
# CSRF / State Parameter Management
# =============================================================================

def generate_state_token():
    """Generate a cryptographically secure state parameter for CSRF protection."""
    state = secrets.token_urlsafe(32)
    session["oauth_state"] = state
    return state


def validate_state_token(state):
    """Validate the state parameter returned from the authorization server."""
    expected = session.pop("oauth_state", None)
    if not expected or not secrets.compare_digest(expected, state):
        logger.warning("State token mismatch — possible CSRF attack")
        return False
    return True


# =============================================================================
# PKCE Support
# =============================================================================

def generate_pkce_pair():
    """Generate PKCE code_verifier and code_challenge."""
    code_verifier = secrets.token_urlsafe(64)
    code_challenge = (
        hashlib.sha256(code_verifier.encode("ascii"))
        .digest()
    )
    import base64
    code_challenge_b64 = (
        base64.urlsafe_b64encode(code_challenge).rstrip(b"=").decode("ascii")
    )
    session["pkce_code_verifier"] = code_verifier
    return code_verifier, code_challenge_b64


