@app.route("/login/<tenant_id>")
def login(tenant_id):
    """
    Initiate the OAuth 2.0 Authorization Code flow with PKCE for a tenant.
    """
    tenant_config = get_tenant_config(tenant_id)
    if not tenant_config:
        abort(404, description=f"Tenant '{tenant_id}' not found")

    # Get the redirect_uri from the request
    redirect_uri = request.args.get("redirect_uri", "")

    if not redirect_uri:
        # Fall back to the first allowed redirect URI
        allowed_uris = tenant_config.get("allowed_redirect_uris", [])
        if allowed_uris:
            redirect_uri = allowed_uris[0]
        else:
            abort(400, description="No redirect_uri provided and no default configured")

    # SECURE validation of the redirect URI
    if not validate_redirect_uri(redirect_uri, tenant_config):
        logger.warning(
            f"Rejected invalid redirect_uri for tenant {tenant_id}: {redirect_uri}"
        )
        abort(400, description="Invalid redirect_uri for this tenant")

    # Store tenant info and redirect_uri in session for the callback
    session["tenant_id"] = tenant_id
    session["redirect_uri"] = redirect_uri

    # Generate CSRF state token
    state = generate_state_token()

    # Generate PKCE challenge
    code_verifier, code_challenge = generate_pkce_pair()

    # Build the authorization URL
    params = {
        "response_type": "code",
        "client_id": tenant_config["client_id"],
        "redirect_uri": redirect_uri,
        "scope": tenant_config["scopes"],
        "state": state,
        "code_challenge": code_challenge,
        "code_challenge_method": "S256",
    }

    authorization_url = (
        f"{tenant_config['authorization_endpoint']}?{urlencode(params)}"
    )

    logger.info(
        f"Initiating OAuth flow for tenant {tenant_id} "
        f"with redirect_uri: {redirect_uri}"
    )

    return redirect(authorization_url)


@app.route("/callback")
def callback():
    """
    Handle the OAuth 2.0 authorization callback.
    Exchange the authorization code for tokens.
    """
    # Validate state parameter (CSRF protection)
    state = request.args.get("state", "")
    if not validate_state_token(state):
        abort(403, description="Invalid state parameter — possible CSRF attack")

    # Check for errors from the authorization server
    error = request.args.get("error")
    if error:
        error_description = request.args.get("error_description", "Unknown error")
        logger.error(f"Authorization error: {error} — {error_description}")
        abort(400, description=f"Authorization failed: {error_description}")

    # Get the authorization code
    code = request.args.get("code")
    if not code:
        abort(400, description="No authorization code received")

    # Retrieve session data
    tenant_id = session.get("tenant_id")
    stored_redirect_uri = session.get("redirect_uri")
    code_verifier = session.pop("pkce_code_verifier", None)

    if not tenant_id or not stored_redirect_uri:
        abort(400, description="Session data missing — please restart the flow")

    tenant_config = get_tenant_config(tenant_id)
    if not tenant_config:
        abort(400, description="Invalid tenant in session")

    # Exchange authorization code for tokens
    token_data = {
        "grant_type": "authorization_code",
        "code": code,
        "redirect_uri": stored_redirect_uri,
        "client_id": tenant_config["client_id"],
        "client_secret": tenant_config["client_secret"],
    }

    if code_verifier:
        token_data["code_verifier"] = code_verifier

    try:
        token_response = requests.post(
            tenant_config["token_endpoint"],
            data=token_data,
            headers={"Accept": "application/json"},
            timeout=10,
        )
        token_response.raise_for_status()
        tokens = token_response.json()
    except requests.RequestException as e:
        logger.error(f"Token exchange failed: {e}")
        abort(500, description="Failed to exchange authorization code for tokens")

    # Store tokens in session (in production, use a secure token store)
    session["access_token"] = tokens.get("access_token")
    session["refresh_token"] = tokens.get("refresh_token")
    session["id_token"] = tokens.get("id_token")

    # Clean up session
    session.pop("tenant_id", None)
    session.pop("redirect_uri", None)

    logger.info(f"Successfully completed OAuth flow for tenant {tenant_id}")

    return jsonify({
        "message": "Authentication successful",
        "tenant": tenant_id,
        "token_type": tokens.get("token_type"),
        "scope": tokens.get("scope"),
        # Never expose actual tokens in a response in production
    })


@app.route("/userinfo/<tenant_id>")
def userinfo(tenant_id):
    """Fetch user info using the stored access token."""
    access_token = session.get("access_token")
    if not access_token:
        abort(401, description="Not authenticated — please login first")

    tenant_config = get_tenant_config(tenant_id)
    if not tenant_config:
        abort(404, description=f"Tenant '{tenant_id}' not found")

    try:
        response = requests.get(
            tenant_config["userinfo_endpoint"],
            headers={
                "Authorization": f"Bearer {access_token}",
                "Accept": "application/json",
            },
            timeout=10,
        )
        response.raise_for_status()
        return jsonify(response.json())
    except requests.RequestException as e:
        logger.error(f"Failed to fetch user info: {e}")
        abort(500, description="Failed to fetch user information")


