@app.route("/security-demo")
def security_demo():
    """
    Demonstrates why substring-based redirect URI validation is dangerous.
    Only available in debug mode.
    """
    if not app.debug:
        abort(404)

    domain = "example.com"
    test_cases = [
        # (URI, expected_secure_result, description)
        ("https://example.com/callback", True, "Exact domain match"),
        ("https://app.example.com/callback", True, "Valid subdomain"),
        ("https://deep.sub.example.com/callback", True, "Deep subdomain"),
        ("https://evil-example.com/callback", False, "Hyphenated lookalike"),
        ("https://example.com.attacker.com/callback", False, "Domain as subdomain of attacker"),
        ("https://attacker.com/?q=example.com", False, "Domain in query string"),
        ("https://attacker.com/example.com", False, "Domain in path"),
        ("http://example.com/callback", False, "HTTP instead of HTTPS"),
        ("javascript://example.com/%0aalert(1)", False, "JavaScript protocol"),
    ]

    results = []
    mock_config = {
        "allowed_redirect_domain": domain,
        "allowed_redirect_uris": ["https://example.com/callback"],
    }

    for uri, expected, description in test_cases:
        insecure_check = domain in uri
        secure_check = validate_redirect_uri(uri, mock_config)
        results.append({
            "uri": uri,
            "description": description,
            "insecure_substring_check": insecure_check,
            "secure_validation": secure_check,
            "expected": expected,
            "insecure_would_be_wrong": insecure_check != expected,
        })

    return jsonify({
        "domain": domain,
        "message": (
            "This demonstrates why 'if domain in redirect_uri' is dangerous. "
            "Look at cases where insecure_would_be_wrong is true."
        ),
        "results": results,
    })


